params.script:
// Script Template: condition_group
// 入力モジュールの出力値をグループ番号に分類（多段分岐用）
// プレースホルダー: OpenAI_診療科_聴取 = 入力元モジュール名（OpenAI モジュール）
// プレースホルダー: {"呼吸器": "1", "消化器": "1", "脳神経": "1", "産婦人科": "1", "救急科": "1", "病理診断科": "1", "わからない": "1", "other": "1"} = 値→グループ番号の JSON オブジェクト
// プレースホルダー: 1 = マッピングに該当しない場合のデフォルトグループ番号
// 出力: グループ番号文字列（"1", "2", ... "10"）

var input = $runner.getModuleResult("OpenAI_診療科_聴取");
var mapping = {"呼吸器": "1", "消化器": "1", "脳神経": "1", "産婦人科": "1", "救急科": "1", "病理診断科": "1", "わからない": "1", "other": "1"};
var group = mapping[input];
if (!group) { group = "1"; }
$runner.setResult(group);
